#ifndef VM_IOT_CONFIG_H
#define VM_IOT_CONFIG_H

#include <string>
#include <cstdint>

namespace vm_iot {

// RTSP 服务端配置
struct ServerConfig {
 uint16_t port = 8554;
 std::string mount = "/live";
};

// 视频采集配置
struct CaptureConfig {
 std::string device = "/dev/video0";
 uint32_t width = 1280;
 uint32_t height = 720;
 uint32_t framerate = 30;
 std::string pixfmt = "NV12";
};

// 编码后端类型
enum class EncoderBackend {
 VAAPI,
 NVENC,
 V4L2M2M,
 X264,
};

// 编码器配置
struct EncoderConfig {
 EncoderBackend backend = EncoderBackend::VAAPI;
 uint32_t bitrate_kbps = 4000;
 uint32_t gop = 30;
 uint32_t bframes = 0;
};

// 日志级别
enum class LogLevel {
 Trace,
 Debug,
 Info,
 Warn,
 Err,
};

// 日志配置
struct LogConfig {
 LogLevel level = LogLevel::Info;
};

// 顶层聚合配置
struct Config {
 ServerConfig server;
 CaptureConfig capture;
 EncoderConfig encoder;
 LogConfig log;

 // 从 YAML 文件加载配置；解析失败抛出 std::runtime_error
 static Config loadFromFile(const std::string& path);
};

// 工具函数：在字符串与枚举之间互转
EncoderBackend parseEncoderBackend(const std::string& s);
const char* toString(EncoderBackend b);

LogLevel parseLogLevel(const std::string& s);
const char* toString(LogLevel lv);

} // namespace vm_iot

#endif //VM_IOT_CONFIG_H
