{"rawEvent":{"message_id":"019e970dc3cf773a91cf407f7f7f2c92","conversation_id":"019e97004e85717aa3c2aff8ca9e1419","tool_call_id":"tooluse_aXNBzgUk75WG8sFRuHLBP4","document":{"file_path":"/home/ubuntu/Desktop/JW/vm_iot/src/app/config.cpp","sub_content":"config.cpp","sub_content_event":"open_editor","sub_content_event_value":"/home/ubuntu/Desktop/JW/vm_iot/src/app/config.cpp","sub_content_tip":"/home/ubuntu/Desktop/JW/vm_iot/src/app/config.cpp","apply_content":"//
// Created by vompom on on 2026/06/05 17:04.
//
// @Description
// 解析 YAML 配置文件，缺省字段使用默认值，非法字段记录 warning 后回退默认。
//

#include "config.h"

#include <algorithm>
#include <cctype>
#include <stdexcept>
#include <string>

#include <spdlog/spdlog.h>
#include <yaml-cpp/yaml.h>

namespace vm_iot {

namespace {

// 转小写工具，便于大小写不敏感地匹配字符串枚举
std::string toLower(std::string s) {
 std::transform(s.begin(), s.end(), s.begin(),
 [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
 return s;
}

// 安全读取标量节点：节点不存在或无效时返回默认值
template <typename T>
T getOr(const YAML::Node& node, const std::string& key, const T& def) {
 if (!node || !node.IsMap()) {
 return def;
 }
 const auto& child = node[key];
 if (!child || !child.IsScalar()) {
 return def;
 }
 try {
 return child.as<T>();
 } catch (const YAML::Exception& e) {
 spdlog::warn("config: 字段 '{}' 解析失败 ({})，使用默认值", key, e.what());
 return def;
 }
}

void parseServer(const YAML::Node& node, ServerConfig& out) {
 out.port = getOr<uint16_t>(node, "port", out.port);
 out.mount = getOr<std::string>(node, "mount", out.mount);
}

void parseCapture(const YAML::Node& node, CaptureConfig& out) {
 out.device = getOr<std::string>(node, "device", out.device);
 out.width = getOr<uint32_t>(node, "width", out.width);
 out.height = getOr<uint32_t>(node, "height", out.height);
 out.framerate = getOr<uint32_t>(node, "framerate", out.framerate);
 out.pixfmt = getOr<std::string>(node, "pixfmt", out.pixfmt);
}

void parseEncoder(const YAML::Node& node, EncoderConfig& out) {
 const auto backendStr = getOr<std::string>(node, "backend", toString(out.backend));
 out.backend = parseEncoderBackend(backendStr);
 out.bitrate_kbps = getOr<uint32_t>(node, "bitrate_kbps", out.bitrate_kbps);
 out.gop = getOr<uint32_t>(node, "gop", out.gop);
 out.bframes = getOr<uint32_t>(node, "bframes", out.bframes);
}

void parseLog(const YAML::Node& node, LogConfig& out) {
 const auto levelStr = getOr<std::string>(node, "level", toString(out.level));
 out.level = parseLogLevel(levelStr);
}

} // namespace

EncoderBackend parseEncoderBackend(const std::string& s) {
 const auto v = toLower(s);
 if (v == "vaapi") return EncoderBackend::VAAPI;
 if (v == "nvenc") return EncoderBackend::NVENC;
 if (v == "v4l2m2m") return EncoderBackend::V4L2M2M;
 if (v == "x264") return EncoderBackend::X264;

 spdlog::warn("config: 未知的 encoder.backend='{}'，回退为 vaapi", s);
 return EncoderBackend::VAAPI;
}

const char* toString(EncoderBackend b) {
 switch (b) {
 case EncoderBackend::VAAPI: return "vaapi";
 case EncoderBackend::NVENC: return "nvenc";
 case EncoderBackend::V4L2M2M: return "v4l2m2m";
 case EncoderBackend::X264: return "x264";
 }
 return "vaapi";
}

LogLevel parseLogLevel(const std::string& s) {
 const auto v = toLower(s);
 if (v == "trace") return LogLevel::Trace;
 if (v == "debug") return LogLevel::Debug;
 if (v == "info") return LogLevel::Info;
 if (v == "warn" || v == "warning") return LogLevel::Warn;
 if (v == "err" || v == "error") return LogLevel::Err;

 spdlog::warn("config: 未知的 log.level='{}'，回退为 info", s);
 return LogLevel::Info;
}

const char* toString(LogLevel lv) {
 switch (lv) {
 case LogLevel::Trace: return "trace";
 case LogLevel::Debug: return "debug";
 case LogLevel::Info: return "info";
 case LogLevel::Warn: return "warn";
 case LogLevel::Err: return "err";
 }
 return "info";
}

Config Config::loadFromFile(const std::string& path) {
 YAML::Node root;
 try {
 root = YAML::LoadFile(path);
 } catch (const YAML::Exception& e) {
 throw std::runtime_error("加载 YAML 配置失败: " + path + " (" + e.what() + ")");
 }

 if (!root || !root.IsMap()) {
 throw std::runtime_error("YAML 配置根节点必须是 map: " + path);
 }

 Config cfg;
 parseServer (root["server"], cfg.server);
 parseCapture(root["capture"], cfg.capture);
 parseEncoder(root["encoder"], cfg.encoder);
 parseLog (root["log"], cfg.log);

 spdlog::debug("config: 加载完成 path={} server={}:{} mount={} device={} {}x{}@{} pixfmt={} "
 "encoder={} bitrate={}kbps gop={} bframes={} log.level={}",
 path,
 "0.0.0.0", cfg.server.port, cfg.server.mount,
 cfg.capture.device, cfg.capture.width, cfg.capture.height,
 cfg.capture.framerate, cfg.capture.pixfmt,
 toString(cfg.encoder.backend), cfg.encoder.bitrate_kbps,
 cfg.encoder.gop, cfg.encoder.bframes,
 toString(cfg.log.level));
 return cfg;
}

} // namespace vm_iot
