/*
 * 把任意字符串转义成可以安全嵌入 gst-parse-launch 双引号字面量的形式。
 *
 * gst-parse-launch 的解析规则（简化版）：
 * - 双引号 " 用来包住带特殊字符的属性值；
 * - 双引号内的 \"、\\、\n、\r、\t 会被还原；
 * - 裸的换行 / 双引号会让解析器立即截断字符串。
 *
 * 因此这里至少要处理：
 * '\\' -> "\\\\"
 * '"' -> "\\\""
 * '\n' -> "\\n"
 * '\r' -> "\\r"
 * '\t' -> "\\t"
 *
 * 其他可见 ASCII 字符原样输出即可。GLSL shader 里偶尔出现的非 ASCII
 * 注释字符也会被原样保留 —— gst-parse-launch 不关心字节级编码。
 */
static std::string escape(const std::string& in) {
 std::string out;
 out.reserve(in.size() + 16);
 for (char ch : in) {
 switch (ch) {
 case '\\': out += "\\\\"; break;
 case '"': out += "\\\""; break;
 case '\n': out += "\\n"; break;
 case '\r': out += "\\r"; break;
 case '\t': out += "\\t"; break;
 default: out += ch; break;
 }
 }
 return out;
}

