( v4l2src device=/dev/video0 do-timestamp=true ! video/x-raw,format=I420,width=1280,height=720,framerate=30/1 ! videoconvert ! video/x-raw,format=RGBA ! glupload ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA ! glshader name=f1 fragment="#version 300 es
precision mediump float;

in  vec2 v_texcoord;
out vec4 fragColor;

uniform sampler2D tex;
uniform vec2  texel;          // (1.0/W, 1.0/H)
uniform float sigma_space;    // 默认 4.0
uniform float sigma_color;    // 默认 0.10

#define R 3                   // 7x7 窗口

void main() {
    vec3 center = texture(tex, v_texcoord).rgb;
    vec3 sum    = vec3(0.0);
    float wsum  = 0.0;

    float inv_2ss = 1.0 / (2.0 * sigma_space * sigma_space);
    float inv_2sc = 1.0 / (2.0 * sigma_color * sigma_color);

    for (int dy = -R; dy <= R; ++dy) {
        for (int dx = -R; dx <= R; ++dx) {
            vec2  off = vec2(float(dx), float(dy)) * texel;
            vec3  s   = texture(tex, v_texcoord + off).rgb;
            float ws  = exp(-float(dx*dx + dy*dy) * inv_2ss);
            vec3  d   = s - center;
            float wc  = exp(-dot(d, d) * inv_2sc);
            float w   = ws * wc;
            sum  += s * w;
            wsum += w;
        }
    }
    fragColor = vec4(sum / wsum, 1.0);
}" vertex="#version 300 es
in vec4 a_position;
in vec2 a_texcoord;
out vec2 v_texcoord;
void main() {
    gl_Position = a_position;
    v_texcoord  = a_texcoord;
}" ! glshader name=f3 fragment="" vertex="#version 300 es
in vec4 a_position;
in vec2 a_texcoord;
out vec2 v_texcoord;
void main() {
    gl_Position = a_position;
    v_texcoord  = a_texcoord;
}" ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA ! gldownload ! video/x-raw,format=RGBA ! videoconvert ! video/x-raw,format=I420 ! queue max-size-buffers=2 leaky=downstream ! x264enc tune=zerolatency speed-preset=ultrafast bitrate=4000 key-int-max=30 bframes=0 ! h264parse config-interval=1 ! rtph264pay name=pay0 pt=96 mtu=1400 )

//
// Created by vompom on on 2026/06/06 09:14.
//
// @Description
//

#include "pipeline_builder.h"

#include <fstream>


std::string PipelineBuilder::encoder_str(const EncoderConfig& e, std::string& src_fmt) {
    std::ostringstream os;
    if (e.backend == "vaapi") {
        src_fmt = "NV12";
        os << "vaapih264enc"
           << " rate-control=cbr"
           << " bitrate=" << e.bitrate_kbps
           << " keyframe-period=" << e.gop
           << " tune=low-power";
    } else if (e.backend == "nvenc") {
        src_fmt = "NV12";
        os << "nvh264enc"
           << " preset=low-latency-hp"
           << " rc-mode=cbr"
           << " bitrate=" << e.bitrate_kbps
           << " gop-size=" << e.gop;
    } else if (e.backend == "v4l2m2m") {
        // src_fmt = "NV12";
        // os << "v4l2h264enc extra-controls=\"controls"
        //    << ",h264_profile=4"
        //    << ",video_bitrate=" << (e.bitrate_kbps * 1000)
        //    << ",h264_i_frame_period=" << e.gop
        //    << ",h264_b_frames=" << e.bframes
        //    << "\"";
        // 使用dmabuf
        src_fmt = "NV12";
        os << "v4l2h264enc"
           << " capture-io-mode=4 output-io-mode=4"      // 双侧 dmabuf
           << " extra-controls=\"controls"
           << ",h264_profile=4"
           << ",video_bitrate=" << (e.bitrate_kbps * 1000)
           << ",h264_i_frame_period=" << e.gop
           << ",h264_b_frames=" << e.bframes
           << "\"";
    } else if (e.backend == "x264") {
        src_fmt = "I420";
        os << "x264enc"
           << " tune=zerolatency"
           << " speed-preset=ultrafast"
           << " bitrate=" << e.bitrate_kbps
           << " key-int-max=" << e.gop
           << " bframes=" << e.bframes;
    } else {
        throw std::runtime_error("unknown encoder backend: " + e.backend);
    }
    return os.str();
}

std::string downstream_for(const std::string& backend) {
    if (backend == "vaapi")   return "queue max-size-buffers=2 leaky=downstream";
    if (backend == "nvenc")   return "nvvideoconvert ! 'video/x-raw(memory:NVMM),format=NV12' ! "
                                     "queue max-size-buffers=2 leaky=downstream";
    if (backend == "v4l2m2m") return "queue max-size-buffers=2 leaky=downstream";
    return "videoconvert ! queue max-size-buffers=2 leaky=downstream"; // x264 软编兜底
}
static std::string read_text(const std::string& path) {
    std::ifstream f(path);
    std::ostringstream ss; ss << f.rdbuf();
    return ss.str();
}
static std::string escape_glsl(const std::string& s) {
    std::string r; r.reserve(s.size() + 16);
    for (char c : s) {
        if (c == '"' || c == '\\') r.push_back('\\');
        r.push_back(c);
    }
    return r;
}
static std::string filter_chain_str(const FilterConfig& fc) {
    std::ostringstream os;
    bool first = true;
    auto sep = [&]{ if (first) first = false; else os << " ! "; };

    if (fc.enable_f1) {
        sep();
        os << "glshader name=f1"
           << " fragment=\""
           << escape_glsl(read_text(fc.shader_dir + "/bilateral.frag")) << "\""
           << " vertex=\""
           << escape_glsl(read_text(fc.shader_dir + "/passthrough.vert")) << "\"";
    }
    if (fc.enable_f3) {
        sep();
        os << "glshader name=f3"
           << " fragment=\""
           << escape_glsl(read_text(fc.shader_dir + "/unsharp.frag")) << "\""
           << " vertex=\""
           << escape_glsl(read_text(fc.shader_dir + "/passthrough.vert")) << "\"";
    }
    if (first) {
        // 全关时给一个 identity 元件，保持链路连续，且仍持有 GLMemory 域
        os << "glcolorconvert";
    }
    return os.str();
}

std::string PipelineBuilder::build(const Config& c, Mode mode) {
    std::string src_fmt;
    std::string enc       = encoder_str(c.encoder, src_fmt);
    std::string filters   = filter_chain_str(c.filter);

    std::ostringstream os;

    if (mode == Mode::Dmabuf) {
        // ---------------- 真机零拷贝路径 ----------------
        os << "( v4l2src device=" << c.capture.device
           << " do-timestamp=true io-mode=4"
           << " ! video/x-raw(memory:DMABuf),format=" << c.capture.pixfmt
           << ",width="     << c.capture.width
           << ",height="    << c.capture.height
           << ",framerate=" << c.capture.framerate << "/1"

           // 上 GL（dmabuf 零拷贝 import 成 GL 纹理）
           << " ! glupload"

           // GL 域内：先转 RGBA，喂给 M4 滤镜段
           << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
           << " ! " << filters
           // 滤镜段输出仍是 GLMemory/RGBA，转回 NV12 再下 GL
           << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=NV12"
           << " ! gldownload ! video/x-raw(memory:DMABuf),format=NV12"

           // M3 §T3.3：按编码器后端切换承接子串（统一 queue 出口）
           << " ! " << downstream_for(c.encoder.backend)

           // 编码器 + 打包
           << " ! " << enc
           << " ! h264parse config-interval=1"
           << " ! rtph264pay name=pay0 pt=96 mtu=1400 )";

    } else {
        // ---------------- mmap 降级路径（UTM / 无 dmabuf 真机）----------------
        // 与 dmabuf 分支共用同一份 filters 子串，差异仅在上下 GL 的桥接
        os << "( v4l2src device=" << c.capture.device << " do-timestamp=true"
           << " ! video/x-raw,format=" << c.capture.pixfmt
           << ",width="     << c.capture.width
           << ",height="    << c.capture.height
           << ",framerate=" << c.capture.framerate << "/1"

           // CPU 转 RGBA -> 上 GL
           << " ! videoconvert ! video/x-raw,format=RGBA"
           << " ! glupload"
           << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"

           // （与 dmabuf 分支完全相同）
           << " ! " << filters

           // 滤镜段输出仍是 GLMemory/RGBA，先在 GL 域内锚定一次 caps，
           // 再 gldownload 回到 SystemMemory，最后 videoconvert 转编码器要的 fmt
           << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
           << " ! gldownload ! video/x-raw,format=RGBA"
           << " ! videoconvert ! video/x-raw,format=" << src_fmt

           // mmap 分支编码器直接吃 SystemMemory，不需要 downstream_for
           << " ! queue max-size-buffers=2 leaky=downstream"
           << " ! " << enc
           << " ! h264parse config-interval=1"
           << " ! rtph264pay name=pay0 pt=96 mtu=1400 )";
    }
    return os.str();
}



static bool try_pipeline(const std::string& launch, int wait_ms = 1500) {
    GError* err = nullptr;
    GstElement* p = gst_parse_launch(launch.c_str(), &err);
    if (!p) {
        LOGW("parse_launch failed: {}", err ? err->message : "?");
        if (err) g_error_free(err);
        return false;
    }
    GstStateChangeReturn r = gst_element_set_state(p, GST_STATE_PAUSED);
    if (r == GST_STATE_CHANGE_FAILURE) {
        gst_element_set_state(p, GST_STATE_NULL);
        gst_object_unref(p);
        return false;
    }
    /* 等一会儿看是否真的进入 PAUSED */
    GstState st;
    gst_element_get_state(p, &st, nullptr, wait_ms * GST_MSECOND);
    bool ok = (st == GST_STATE_PAUSED);
    gst_element_set_state(p, GST_STATE_NULL);
    gst_object_unref(p);
    return ok;
}

PipelineBuilder::Mode PipelineBuilder::detect_mode(const Config& c) {
    /* 先试 dmabuf */
    // auto launch_dma = build(c, Mode::Dmabuf);
    // if (try_pipeline(launch_dma)) {
    //     LOGI("dmabuf pipeline OK, using zero-copy path");
    //     return Mode::Dmabuf;
    // }
    // LOGW("dmabuf path failed, fallback to mmap+videoconvert");
    // todo:: dmabuf utm 目前还不支持，后面使用硬件再说
    return Mode::Mmap;
}

( v4l2src device=/dev/video0 do-timestamp=true ! video/x-raw,format=I420,width=1280,height=720,framerate=30/1 ! videoconvert ! video/x-raw,format=RGBA ! glupload ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA ! glshader name=f1 fragment="#version 300 es
precision mediump float;

in  vec2 v_texcoord;
out vec4 fragColor;

uniform sampler2D tex;
uniform vec2  texel;          // (1.0/W, 1.0/H)
uniform float sigma_space;    // 默认 4.0
uniform float sigma_color;    // 默认 0.10

#define R 3                   // 7x7 窗口

void main() {
    vec3 center = texture(tex, v_texcoord).rgb;
    vec3 sum    = vec3(0.0);
    float wsum  = 0.0;

    float inv_2ss = 1.0 / (2.0 * sigma_space * sigma_space);
    float inv_2sc = 1.0 / (2.0 * sigma_color * sigma_color);

    for (int dy = -R; dy <= R; ++dy) {
        for (int dx = -R; dx <= R; ++dx) {
            vec2  off = vec2(float(dx), float(dy)) * texel;
            vec3  s   = texture(tex, v_texcoord + off).rgb;
            float ws  = exp(-float(dx*dx + dy*dy) * inv_2ss);
            vec3  d   = s - center;
            float wc  = exp(-dot(d, d) * inv_2sc);
            float w   = ws * wc;
            sum  += s * w;
            wsum += w;
        }
    }
    fragColor = vec4(sum / wsum, 1.0);
}" vertex="#version 300 es
in vec4 a_position;
in vec2 a_texcoord;
out vec2 v_texcoord;
void main() {
    gl_Position = a_position;
    v_texcoord  = a_texcoord;
}" ! glshader name=f3 fragment="" vertex="#version 300 es
in vec4 a_position;
in vec2 a_texcoord;
out vec2 v_texcoord;
void main() {
    gl_Position = a_position;
    v_texcoord  = a_texcoord;
}" ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA ! gldownload ! video/x-raw,format=RGBA ! videoconvert ! video/x-raw,format=I420 ! queue max-size-buffers=2 leaky=downstream ! x264enc tune=zerolatency speed-preset=ultrafast bitrate=4000 key-int-max=30 bframes=0 ! h264parse config-interval=1 ! rtph264pay name=pay0 pt=96 mtu=1400 )

//
// Created by vompom on on 2026/06/05 17:08.
//
// @Description
//

#include "rtsp_server.h"
#include "pipeline_builder.h"
#include "log.h"
#include <string>


void RtspServer::on_client_connected(GstRTSPServer*, GstRTSPClient* c, gpointer) {
    GstRTSPConnection* conn = gst_rtsp_client_get_connection(c);
    const gchar* ip = gst_rtsp_connection_get_ip(conn);
    LOGI("client connected: {}", ip ? ip : "unknown");
}

bool RtspServer::start(const Config& cfg, PipelineBuilder::Mode mode) {
    server_ = gst_rtsp_server_new();
    if (!server_) {
        LOGE("gst_rtsp_server_new failed");
        return false;
    }

    std::string port_str = std::to_string(cfg.server.port);
    gst_rtsp_server_set_service(server_, port_str.c_str());

    mounts_  = gst_rtsp_server_get_mount_points(server_);
    factory_ = gst_rtsp_media_factory_new();

    std::string launch = PipelineBuilder::build(cfg, mode);
    LOGI("rtsp launch: {}", launch);
    gst_rtsp_media_factory_set_launch(factory_, launch.c_str());

    /* shared=TRUE: 多客户端共享同一份编码输出，CPU 不会随客户端数翻倍 */
    gst_rtsp_media_factory_set_shared(factory_, TRUE);

    /* 默认协议优先 UDP，TCP 兜底 */
    gst_rtsp_media_factory_set_protocols(factory_,
        (GstRTSPLowerTrans)(GST_RTSP_LOWER_TRANS_UDP | GST_RTSP_LOWER_TRANS_TCP));

    gst_rtsp_mount_points_add_factory(mounts_, cfg.server.mount.c_str(), factory_);
    /* add_factory 会持有 factory 的引用，下面要释放本地这一份 */
    g_object_unref(mounts_);
    mounts_ = nullptr;
    /* factory 同理: 用完释放本地引用，server 内部还持有一份 */

    g_signal_connect(server_, "client-connected",
                     G_CALLBACK(&RtspServer::on_client_connected), this);

    source_id_ = gst_rtsp_server_attach(server_, nullptr);
    if (source_id_ == 0) {
        LOGE("gst_rtsp_server_attach failed (port {} in use?)", cfg.server.port);
        return false;
    }

    LOGI("rtsp ready: rtsp://0.0.0.0:{}{}", cfg.server.port, cfg.server.mount);
    return true;
}

void RtspServer::stop() {
    if (source_id_) {
        g_source_remove(source_id_);
        source_id_ = 0;
    }
    if (server_) {
        g_object_unref(server_);
        server_ = nullptr;
    }
}

