 std::string r; r.reserve(s.size() + 16);
 for (char c : s) {
 switch (c) {
 case '\\': r += "\\\\"; break;
 case '"' : r += "\\\""; break;
 case '\n': r += "\\n"; break;
 case '\r': r += "\\r"; break;
 case '\t': r += "\\t"; break;
 default : r += c; break;
 }
 }
 return r;
}","new_string":"// 给 gst_parse_launch 的属性值 "..." 用：只转义 \ 和 "，
// 真换行 / 制表符必须以原始字节透传，否则 GLSL 里 // 单行注释会把整段 shader 吃成一行，
// 编译器报 "unexpected end of file"。
static std::string escape_glsl(const std::string& s) {
 std::string r; r.reserve(s.size() + 16);
 for (char c : s) {
 switch (c) {
 case '\\': r += "\\\\"; break;
 case '"' : r += "\\\""; break;
 default : r += c; break; // \n \r \t 等全部原样保留
 }
 }
 return r;
}","apply_mode":"apply_only"}},"timestamp":1780928827,"type":"TOOL_CALL_ARGS"}

