{"rawEvent":{"message_id":"019ea7be57177e4a8ee94bf4b09297f6","conversation_id":"019e97004e85717aa3c2aff8ca9e1419","tool_call_id":"tooluse_J0osCnGMy9s3zVtjaIsrDC","document":{"file_path":"/home/ubuntu/Desktop/JW/vm_iot/src/rtsp/pipeline_builder.cpp","sub_content":"pipeline_builder.cpp","sub_content_event":"open_editor","sub_content_event_value":"/home/ubuntu/Desktop/JW/vm_iot/src/rtsp/pipeline_builder.cpp","sub_content_tip":"/home/ubuntu/Desktop/JW/vm_iot/src/rtsp/pipeline_builder.cpp","old_string":" } else {
 // ---------------- mmap 降级路径（UTM / 无 dmabuf 真机）----------------
 // 与 dmabuf 分支共用同一份 filters 子串，差异仅在上下 GL 的桥接
 os << "( v4l2src device=" << c.capture.device << " do-timestamp=true"
 << " ! video/x-raw,format=" << c.capture.pixfmt
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"

 // CPU 转 RGBA -> 上 GL
 // 注意：所有中间 caps 都必须锁死全部字段（包括 interlace-mode），
 // 否则下游重协商时会丢掉未锁字段，与上游 caps 不匹配到 v4l2src 失败
 << " ! videoconvert ! video/x-raw,format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"
 << ",interlace-mode=progressive"
 << " ! glupload"
 << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"
 << ",interlace-mode=progressive"

 // （与 dmabuf 分支完全相同）
 << " ! " << filters

 // 滤镜段输出仍是 GLMemory/RGBA，先在 GL 域内锚定一次 caps，
 // 再 gldownload 回到 SystemMemory，最后 videoconvert 转编码器要的 fmt
 << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"
 << ",interlace-mode=progressive"
 << " ! gldownload ! video/x-raw,format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"
 << ",interlace-mode=progressive"
 << " ! videoconvert ! video/x-raw,format=" << src_fmt
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"
 << ",interlace-mode=progressive"

 // mmap 分支编码器直接吃 SystemMemory，不需要 downstream_for
 << " ! queue max-size-buffers=2 leaky=downstream"
 << " ! " << enc
 << " ! h264parse config-interval=1"","new_string":" } else {
 // ---------------- mmap 降级路径（UTM / 无 dmabuf 真机）----------------
 // UTM 等虚拟环境下 v4l2 设备的 framerate 实际并不严格 = 声明值，
 // 而 glshader 在 transform_caps 时会主动丢掉部分字段（如 interlace-mode/framerate 范围），
 // 这两件事叠加会让"重协商时回流到 v4l2src"的 caps 与 v4l2src 已固定 caps 不匹配 → not-negotiated。
 //
 // 关键修复：在 v4l2src 后立刻插 videorate，把上游 caps "夯死并隔断"，
 // GL 段无论怎么折腾都不会反向冒泡到 v4l2src。
 // 一旦有 videorate 隔断，GL 段的中间 caps 只需锁 format/width/height 即可，
 // 不锁 framerate、不锁 interlace-mode，避免 glshader 丢字段引发的二次冲突。
 os << "( v4l2src device=" << c.capture.device << " do-timestamp=true"
 << " ! video/x-raw,format=" << c.capture.pixfmt
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"

 // 帧率隔断：把上游"动态/抖动"的 framerate 强制为严格 N/1
 << " ! videorate"
 << " ! video/x-raw,framerate=" << c.capture.framerate << "/1"

 // CPU 转 RGBA -> 上 GL
 << " ! videoconvert ! video/x-raw,format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << " ! glupload"
 << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height

 // （与 dmabuf 分支完全相同）
 << " ! " << filters

 // 滤镜段输出仍是 GLMemory/RGBA，先在 GL 域内锚定一次 caps，
 // 再 gldownload 回到 SystemMemory，最后 videoconvert 转编码器要的 fmt
 << " ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << " ! gldownload ! video/x-raw,format=RGBA"
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << " ! videoconvert ! video/x-raw,format=" << src_fmt
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height

 // mmap 分支编码器直接吃 SystemMemory，不需要 downstream_for
 << " ! queue max-size-buffers=2 leaky=downstream"
 << " ! " << enc
 << " ! h264parse config-interval=1"","apply_mode":"apply_only"}},"timestamp":1780930869,"type":"TOOL_CALL_ARGS"}

