 // ---------------- mmap 降级路径（UTM / 无 dmabuf 真机）----------------
 // UTM 等虚拟环境下 v4l2 设备的 framerate 实际并不严格 = 声明值，
 // 而 glshader 在 transform_caps 时会主动丢掉部分字段（如 interlace-mode/framerate 范围），
 // 这两件事叠加会让"重协商时回流到 v4l2src"的 caps 与 v4l2src 已固定 caps 不匹配 → not-negotiated。
 //
 // 关键修复：在 v4l2src 后立刻插 videorate，把上游 caps "夯死并隔断"，
 // GL 段无论怎么折腾都不会反向冒泡到 v4l2src。
 // 一旦有 videorate 隔断，GL 段的中间 caps 只需锁 format/width/height 即可，
 // 不锁 framerate、不锁 interlace-mode，避免 glshader 丢字段引发的二次冲突。
 os << "( v4l2src device=" << c.capture.device << " do-timestamp=true"
 << " ! video/x-raw,format=" << c.capture.pixfmt
 << ",width=" << c.capture.width
 << ",height=" << c.capture.height
 << ",framerate=" << c.capture.framerate << "/1"

 // 帧率隔断：把上游"动态/抖动"的 framerate 强制为严格 N/1
 << " ! videorate"
 << " ! video/x-raw,framerate=" << c.capture.framerate << "/1"

