attribute vec4 a_position;
attribute vec2 a_texcoord;
varying   vec2 v_texcoord;

void main() {
    gl_Position = a_position;
    v_texcoord  = a_texcoord;
}" ! glcolorconvert ! video/x-raw(memory:GLMemory),format=RGBA,width=1280,height=720 ! gldownload ! video/x-raw,format=RGBA,width=1280,height=720 ! videoconvert ! video/x-raw,format=I420,width=1280,height=720 ! queue max-size-buffers=2 leaky=downstream ! x264enc tune=zerolatency speed-preset=ultrafast bitrate=4000 key-int-max=30 bframes=0 ! h264parse config-interval=1 ! rtph264pay name=pay0 pt=96 mtu=1400 )

